void quicksort(int arr[], int s, int e) {
    if (s < e) {
        int p = partition(arr, s, e);
        quicksort(arr, s, p - 1);
        quicksort(arr, p + 1, e);
    }
}

int partition(int arr[], int s, int e) {
    int pivot = arr[e];
    int i = s - 1;
    for (int j = s; j < e; j++) {
        if (arr[j] <= pivot) {
            i++;
            int temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
    }
    int temp = arr[i + 1];
    arr[i + 1] = arr[e];
    arr[e] = temp;
    return i + 1;
}

